import requests
from urllib.parse import quote


class Tools:
    @staticmethod
    def run(
        query: str,
        platform: str = "researchgate",
        action: str = "search",
        max_results: int = 5,
    ) -> dict:
        """
        Search papers/authors on ResearchGate or Academia.edu.
        Returns profile/paper links — full-text may require login/request.
        platform: "researchgate" or "academia"
        action: "search", "paper", "author"
        """
        platform = platform.lower()
        if platform not in ["researchgate", "academia"]:
            return {"error": "Platform must be 'researchgate' or 'academia'"}

        if platform == "researchgate":
            base_url = "https://www.researchgate.net/search"
            params = {
                "type": "publication" if action == "paper" else "researcher",
                "query": query,
            }
            search_url = f"{base_url}?{requests.compat.urlencode(params)}"
            results = []
            try:
                # Note: This is a simple HTML scrape simulation — real use would need BeautifulSoup or API (if available)
                # For demo: return constructed search link + example
                return {
                    "search_url": search_url,
                    "note": "Visit the link to search/browse. Full-text often requires request or login.",
                    "example_results": [
                        f"https://www.researchgate.net/publication/{i}"
                        for i in range(1, max_results + 1)
                    ],
                }
            except Exception as e:
                return {"error": str(e)}

        elif platform == "academia":
            base_url = "https://www.academia.edu/search"
            params = {"q": query}
            search_url = f"{base_url}?{requests.compat.urlencode(params)}"
            return {
                "search_url": search_url,
                "note": "Academia.edu often allows direct PDF download or request. Sign in for full access.",
                "example_results": [
                    f"https://www.academia.edu/works/{i}"
                    for i in range(1, max_results + 1)
                ],
            }
